type TenantContext = {
  tenantId: string
  userId: string
  plan: string
  keyPolicy: "user_only" | "tenant_first" | "platform_only"
}

async function handleChat(req, res) {
  const identity = await authenticateAppUser(req)
  const ctx = await resolveTenantContext(identity)

  await enforceQuota(ctx)
  const cred = await resolveCredential(ctx) 
  // returns masked metadata + secure handle, not raw key if possible

  const client = await anthropicClientFromCredential(cred)
  const result = await client.messages.create({
    model: pickModel(ctx),
    max_tokens: 1024,
    messages: buildMessages(req.body, ctx),
  })

  await recordUsage({
    tenantId: ctx.tenantId,
    userId: ctx.userId,
    credentialSource: cred.source,
    model: result.model,
    usage: result.usage
  })

  res.json(normalizeResult(result))
}
